external_knowledge:
- "Highly valued" refers to products with a price greater than 100;
- "Well-stocked" refers to products with a stock quantity greater than 50;
- "Users' praise is as bright as the stars in the sky" refers to products with an average rating greater than 4.

sql:
SELECT title
FROM products
WHERE price > 100 AND stock_quantity > 50 AND average_rating > 4;

external_knowledge:
- 'Featured products' are those marked with `is_featured = 1`;
- The query ensures that products without reviews are included with a default average rating of 0;
- The results are ordered alphabetically by product title.

sql:
SELECT COUNT(*) AS total_featured_products
FROM products
WHERE is_featured = 1;

